1	import { randomUUID } from 'node:crypto';
2	
3	import { BadRequestException, Injectable, Logger } from '@nestjs/common';
4	import { InjectQueue } from '@nestjs/bullmq';
5	import { Queue } from 'bullmq';
6	
7	import { CacheService } from '@modules/cache/cache.service';
8	import { Namespaces } from '@modules/cache/types/cache.interface';
9	import { EnvConfigService } from '@modules/env-config/env-config.service';
10	import { JiraInstallationModel } from '@modules/jira/db/jira-installations.model';
11	import { JiraApiService } from '@modules/jira/jira-api.service';
12	import { IJiraInstallationBase } from '@modules/jira/types/jira-installation.interface';
13	
14	import { JIRA_CLIENT_ID, JIRA_CALLBACK_URL } from '@constants/env-variables.constant';
15	
16	interface IInstallStateValue {
17		companyId: string;
18		userId: string;
19	}
20	
21	const STATE_TTL_MS = 5 * 60 * 1000;
22	const ATLASSIAN_AUTH_URL = 'https://auth.atlassian.com/authorize';
23	
24	@Injectable()
25	export class JiraInstallService {
26		private readonly logger = new Logger(JiraInstallService.name);
27	
28		constructor(
29			private readonly configService: EnvConfigService,
30			private readonly cacheService: CacheService,
31			private readonly jiraApiService: JiraApiService,
32			private readonly installationModel: JiraInstallationModel,
33			@InjectQueue('jira') private readonly jiraQueue: Queue,
34		) {}
35	
36		async initiateConnect({
37			companyId,
38			userId,
39		}: {
40			companyId: string;
41			userId: string;
42		}): Promise<string> {
43			const state = randomUUID();
44	
45			await this.cacheService.set({
46				namespace: Namespaces.JIRA_INSTALL_STATE,
47				key: state,
48				value: { companyId, userId } satisfies IInstallStateValue,
49				ttl: STATE_TTL_MS,
50			});
51	
52			const clientId = this.configService.get<string>({ key: JIRA_CLIENT_ID });
53			const redirectUri = this.configService.get<string>({ key: JIRA_CALLBACK_URL });
54			const scopes = 'read:jira-work read:jira-user offline_access';
55	
56			return (
57				`${ATLASSIAN_AUTH_URL}?audience=api.atlassian.com` +
58				`&client_id=${clientId}` +
59				`&scope=${encodeURIComponent(scopes)}` +
60				`&redirect_uri=${encodeURIComponent(redirectUri)}` +
61				`&state=${state}` +
62				`&response_type=code` +
63				`&prompt=consent`
64			);
65		}
66	
67		async handleCallback({
68			code,
69			state,
70		}: {
71			code: string;
72			state: string;
73		}): Promise<IJiraInstallationBase> {
74			const stateData = await this.cacheService.get<IInstallStateValue>({
75				namespace: Namespaces.JIRA_INSTALL_STATE,
76				key: state,
77			});
78	
79			if (!stateData) {
80				throw new BadRequestException('Invalid or expired state token');
81			}
82	
83			await this.cacheService.deleteOne({
84				namespace: Namespaces.JIRA_INSTALL_STATE,
85				key: state,
86			});
87	
88			const tokens = await this.jiraApiService.exchangeCode({ code });
89	
90			const resources = await this.jiraApiService.getAccessibleResources({
91				accessToken: tokens.access_token,
92			});
93	
94			const resource = resources[0];
95	
96			if (!resource) {
97				throw new BadRequestException('No Jira Cloud sites found for this account');
98			}
99	
100			const tokenExpiresAt = new Date(Date.now() + tokens.expires_in * 1000);
101	
102			const installation = await this.installationModel.create({
103				data: {
104					company_id: stateData.companyId,
105					cloud_id: resource.id,
106					site_url: resource.url,
107					access_token: tokens.access_token,
108					refresh_token: tokens.refresh_token,
109					token_expires_at: tokenExpiresAt,
110				},
111			});
112	
113			void this.jiraQueue.add(
114				'discover_projects',
115				{ installationDbId: installation._id },
116				{ attempts: 3, backoff: { type: 'exponential', delay: 5000 } },
117			);
118	
119			this.logger.debug(`Created jira installation ${installation._id} for company ${stateData.companyId}`);
120			return installation;
121		}
122	
123		async disconnect({
124			installationDbId,
125			companyId,
126		}: {
127			installationDbId: string;
128			companyId: string;
129		}): Promise<void> {
130			await this.installationModel.markUninstalled({
131				id: installationDbId,
132				companyId,
133			});
134	
135			this.logger.debug(`Disconnected jira installation ${installationDbId} for company ${companyId}`);
136		}
137	}
