1	import { HttpService } from '@nestjs/axios';
2	import { Injectable, Logger } from '@nestjs/common';
3	
4	import { EnvConfigService } from '@modules/env-config/env-config.service';
5	import { JiraInstallationModel } from '@modules/jira/db/jira-installations.model';
6	import {
7		IAtlassianResource,
8		IAtlassianTokenResponse,
9		IJiraApiBoardResponse,
10		IJiraApiProject,
11		IJiraApiSearchResponse,
12		IJiraApiSprintResponse,
13		IJiraApiWorklog,
14	} from '@modules/jira/types/jira-api.interface';
15	import { IJiraInstallationBase } from '@modules/jira/types/jira-installation.interface';
16	
17	import { JIRA_CLIENT_ID, JIRA_CLIENT_SECRET, JIRA_CALLBACK_URL } from '@constants/env-variables.constant';
18	
19	const TOKEN_REFRESH_BUFFER_MS = 5 * 60 * 1000;
20	const ATLASSIAN_TOKEN_URL = 'https://auth.atlassian.com/oauth/token';
21	const ATLASSIAN_RESOURCES_URL = 'https://api.atlassian.com/oauth/token/accessible-resources';
22	
23	@Injectable()
24	export class JiraApiService {
25		private readonly logger = new Logger(JiraApiService.name);
26	
27		constructor(
28			private readonly httpService: HttpService,
29			private readonly configService: EnvConfigService,
30			private readonly installationModel: JiraInstallationModel,
31		) {}
32	
33		async exchangeCode({
34			code,
35		}: {
36			code: string;
37		}): Promise<IAtlassianTokenResponse> {
38			const { data } = await this.httpService.axiosRef.post<IAtlassianTokenResponse>(
39				ATLASSIAN_TOKEN_URL,
40				{
41					grant_type: 'authorization_code',
42					client_id: this.configService.get<string>({ key: JIRA_CLIENT_ID }),
43					client_secret: this.configService.get<string>({ key: JIRA_CLIENT_SECRET }),
44					redirect_uri: this.configService.get<string>({ key: JIRA_CALLBACK_URL }),
45					code,
46				},
47			);
48			return data;
49		}
50	
51		async getAccessibleResources({
52			accessToken,
53		}: {
54			accessToken: string;
55		}): Promise<IAtlassianResource[]> {
56			const { data } = await this.httpService.axiosRef.get<IAtlassianResource[]>(
57				ATLASSIAN_RESOURCES_URL,
58				{ headers: { Authorization: `Bearer ${accessToken}` } },
59			);
60			return data;
61		}
62	
63		async getValidToken({
64			installation,
65		}: {
66			installation: IJiraInstallationBase;
67		}): Promise<string> {
68			const expiresAt = new Date(installation.token_expires_at).getTime();
69			const now = Date.now();
70	
71			if (expiresAt - now > TOKEN_REFRESH_BUFFER_MS) {
72				return installation.access_token;
73			}
74	
75			try {
76				const refreshed = await this.refreshToken({
77					refreshToken: installation.refresh_token,
78				});
79	
80				const tokenExpiresAt = new Date(Date.now() + refreshed.expires_in * 1000);
81	
82				await this.installationModel.updateTokens({
83					id: installation._id,
84					accessToken: refreshed.access_token,
85					refreshToken: refreshed.refresh_token,
86					tokenExpiresAt,
87				});
88	
89				this.logger.debug(`Refreshed token for installation ${installation._id}`);
90				return refreshed.access_token;
91			} catch (error) {
92				await this.installationModel.markNeedsReauth({ id: installation._id });
93				this.logger.error(
94					`Token refresh failed for installation ${installation._id}: ${(error as Error).message}`,
95				);
96				throw error;
97			}
98		}
99	
100		async listProjects({
101			cloudId,
102			token,
103		}: {
104			cloudId: string;
105			token: string;
106		}): Promise<IJiraApiProject[]> {
107			const base = this.apiBase({ cloudId });
108			const projects: IJiraApiProject[] = [];
109			let startAt = 0;
110			const maxResults = 50;
111	
112			while (true) {
113				const { data } = await this.httpService.axiosRef.get<{
114					values: IJiraApiProject[];
115					isLast: boolean;
116				}>(`${base}/project/search`, {
117					headers: { Authorization: `Bearer ${token}` },
118					params: { startAt, maxResults, typeKey: 'software' },
119				});
120	
121				projects.push(...data.values);
122				if (data.isLast || data.values.length === 0) break;
123				startAt += maxResults;
124			}
125	
126			return projects;
127		}
128	
129		async searchIssues({
130			cloudId,
131			token,
132			jql,
133			startAt,
134		}: {
135			cloudId: string;
136			token: string;
137			jql: string;
138			startAt: number;
139		}): Promise<IJiraApiSearchResponse> {
140			const base = this.apiBase({ cloudId });
141			const { data } = await this.httpService.axiosRef.post<IJiraApiSearchResponse>(
142				`${base}/search/jql`,
143				{
144					jql,
145					startAt,
146					maxResults: 100,
147					expand: ['changelog'],
148					fields: [
149						'summary', 'issuetype', 'status', 'priority',
150						'assignee', 'reporter', 'customfield_10016',
151						'resolutiondate', 'created', 'updated',
152					],
153				},
154				{ headers: { Authorization: `Bearer ${token}` } },
155			);
156			return data;
157		}
158	
159		async getWorklogsForIssue({
160			cloudId,
161			token,
162			issueId,
163		}: {
164			cloudId: string;
165			token: string;
166			issueId: string;
167		}): Promise<IJiraApiWorklog[]> {
168			const base = this.apiBase({ cloudId });
169			const { data } = await this.httpService.axiosRef.get<{
170				worklogs: IJiraApiWorklog[];
171			}>(`${base}/issue/${issueId}/worklog`, {
172				headers: { Authorization: `Bearer ${token}` },
173				params: { maxResults: 5000 },
174			});
175			return data.worklogs;
176		}
177	
178		async listBoards({
179			cloudId,
180			token,
181			projectKeyOrId,
182		}: {
183			cloudId: string;
184			token: string;
185			projectKeyOrId: string;
186		}): Promise<IJiraApiBoardResponse> {
187			const agileBase = this.agileBase({ cloudId });
188			const { data } = await this.httpService.axiosRef.get<IJiraApiBoardResponse>(
189				`${agileBase}/board`,
190				{
191					headers: { Authorization: `Bearer ${token}` },
192					params: { projectKeyOrId, maxResults: 50 },
193				},
194			);
195			return data;
196		}
197	
198		async listSprints({
199			cloudId,
200			token,
201			boardId,
202			startAt,
203		}: {
204			cloudId: string;
205			token: string;
206			boardId: number;
207			startAt: number;
208		}): Promise<IJiraApiSprintResponse> {
209			const agileBase = this.agileBase({ cloudId });
210			const { data } = await this.httpService.axiosRef.get<IJiraApiSprintResponse>(
211				`${agileBase}/board/${boardId}/sprint`,
212				{
213					headers: { Authorization: `Bearer ${token}` },
214					params: { startAt, maxResults: 50 },
215				},
216			);
217			return data;
218		}
219	
220		private async refreshToken({
221			refreshToken,
222		}: {
223			refreshToken: string;
224		}): Promise<IAtlassianTokenResponse> {
225			const { data } = await this.httpService.axiosRef.post<IAtlassianTokenResponse>(
226				ATLASSIAN_TOKEN_URL,
227				{
228					grant_type: 'refresh_token',
229					client_id: this.configService.get<string>({ key: JIRA_CLIENT_ID }),
230					client_secret: this.configService.get<string>({ key: JIRA_CLIENT_SECRET }),
231					refresh_token: refreshToken,
232				},
233			);
234			return data;
235		}
236	
237		private apiBase({ cloudId }: { cloudId: string }): string {
238			return `https://api.atlassian.com/ex/jira/${cloudId}/rest/api/3`;
239		}
240	
241		private agileBase({ cloudId }: { cloudId: string }): string {
242			return `https://api.atlassian.com/ex/jira/${cloudId}/rest/agile/1.0`;
243		}
244	}
