1	import { InjectQueue } from '@nestjs/bullmq';
2	import { Injectable, Logger } from '@nestjs/common';
3	import { Queue } from 'bullmq';
4	
5	import { JiraChangelogModel } from '@modules/jira/db/jira-changelog.model';
6	import { JiraInstallationModel } from '@modules/jira/db/jira-installations.model';
7	import { JiraIssueModel } from '@modules/jira/db/jira-issues.model';
8	import { JiraProjectModel } from '@modules/jira/db/jira-projects.model';
9	import { JiraSprintModel } from '@modules/jira/db/jira-sprints.model';
10	import { JiraWorklogModel } from '@modules/jira/db/jira-worklogs.model';
11	import { JiraApiService } from '@modules/jira/jira-api.service';
12	import { IJiraApiIssue } from '@modules/jira/types/jira-api.interface';
13	import { IJiraIssueBase } from '@modules/jira/types/jira-installation.interface';
14	
15	const THREE_YEARS_MS = 3 * 365 * 24 * 60 * 60 * 1000;
16	
17	@Injectable()
18	export class JiraSyncService {
19		private readonly logger = new Logger(JiraSyncService.name);
20	
21		constructor(
22			private readonly installationModel: JiraInstallationModel,
23			private readonly projectModel: JiraProjectModel,
24			private readonly issueModel: JiraIssueModel,
25			private readonly changelogModel: JiraChangelogModel,
26			private readonly worklogModel: JiraWorklogModel,
27			private readonly sprintModel: JiraSprintModel,
28			private readonly jiraApiService: JiraApiService,
29			@InjectQueue('jira') private readonly jiraQueue: Queue,
30		) {}
31	
32		async discoverProjects({ installationDbId }: { installationDbId: string }): Promise<void> {
33			const installation = await this.installationModel.findById({ id: installationDbId });
34	
35			if (!installation) {
36				this.logger.warn(`Installation ${installationDbId} not found`);
37				return;
38			}
39	
40			const token = await this.jiraApiService.getValidToken({ installation });
41			const projects = await this.jiraApiService.listProjects({
42				cloudId: installation.cloud_id,
43				token,
44			});
45	
46			await this.projectModel.upsertMany({ installationId: installationDbId, projects });
47	
48			const savedProjects = await this.projectModel.findByInstallationId({
49				installationId: installationDbId,
50			});
51	
52			for (const project of savedProjects) {
53				await this.jiraQueue.add(
54					'sync_project',
55					{
56						installationDbId,
57						projectDbId: project._id,
58						projectKey: project.project_key,
59						projectId: project.project_id,
60					},
61					{ attempts: 3, backoff: { type: 'exponential', delay: 5000 } },
62				);
63			}
64	
65			this.logger.debug(
66				`Enqueued sync for ${savedProjects.length} projects in installation ${installationDbId}`,
67			);
68		}
69	
70		async syncProject({
71			installationDbId,
72			projectDbId,
73			projectKey,
74		}: {
75			installationDbId: string;
76			projectDbId: string;
77			projectKey: string;
78		}): Promise<void> {
79			const installation = await this.installationModel.findById({ id: installationDbId });
80	
81			if (!installation) {
82				this.logger.warn(`Installation ${installationDbId} not found`);
83				return;
84			}
85	
86			const projects = await this.projectModel.findByInstallationId({
87				installationId: installationDbId,
88			});
89			const project = projects.find((p) => p._id === projectDbId);
90	
91			if (!project) {
92				this.logger.warn(`Project ${projectDbId} not found`);
93				return;
94			}
95	
96			const token = await this.jiraApiService.getValidToken({ installation });
97	
98			const since = project.last_synced_at
99				? project.last_synced_at
100				: new Date(Date.now() - THREE_YEARS_MS);
101	
102			const sinceStr = since.toISOString().split('T')[0] ?? since.toISOString();
103			const jql = `project = "${projectKey}" AND updated >= "${sinceStr}" ORDER BY updated ASC`;
104	
105			await this.fetchAndStoreIssues({
106				installationDbId,
107				projectDbId,
108				cloudId: installation.cloud_id,
109				token,
110				jql,
111			});
112	
113			await this.fetchAndStoreSprints({
114				installationDbId,
115				projectKey,
116				cloudId: installation.cloud_id,
117				token,
118			});
119	
120			await this.projectModel.updateLastSyncedAt({ id: projectDbId });
121	
122			this.logger.debug(`Sync complete for project ${projectKey} in installation ${installationDbId}`);
123		}
124	
125		async pollAllInstallations(): Promise<void> {
126			const installations = await this.installationModel.findAllActive();
127	
128			for (const installation of installations) {
129				await this.jiraQueue.add(
130					'discover_projects',
131					{ installationDbId: installation._id },
132					{ attempts: 3, backoff: { type: 'exponential', delay: 5000 } },
133				);
134			}
135	
136			this.logger.debug(`Triggered discover_projects for ${installations.length} active installations`);
137		}
138	
139		private async fetchAndStoreIssues({
140			installationDbId,
141			projectDbId,
142			cloudId,
143			token,
144			jql,
145		}: {
146			installationDbId: string;
147			projectDbId: string;
148			cloudId: string;
149			token: string;
150			jql: string;
151		}): Promise<void> {
152			let startAt = 0;
153			const pageSize = 100;
154	
155			while (true) {
156				const response = await this.jiraApiService.searchIssues({
157					cloudId,
158					token,
159					jql,
160					startAt,
161				});
162	
163				if (response.issues.length === 0) break;
164	
165				const savedIssues = await this.issueModel.upsertMany({
166					issues: response.issues.map((issue) => ({
167						installation_id: installationDbId,
168						project_id: projectDbId,
169						issue_key: issue.key,
170						issue_id: issue.id,
171						issue_type: issue.fields.issuetype?.name ?? null,
172						status: issue.fields.status?.name ?? null,
173						priority: issue.fields.priority?.name ?? null,
174						assignee_id: issue.fields.assignee?.accountId ?? null,
175						reporter_id: issue.fields.reporter?.accountId ?? null,
176						story_points: issue.fields.customfield_10016 ?? null,
177						updated_at: new Date(issue.fields.updated),
178						resolved_at: issue.fields.resolutiondate
179							? new Date(issue.fields.resolutiondate)
180							: null,
181					})),
182				});
183	
184				await this.storeChangelogs({
185					installationDbId,
186					issues: response.issues,
187					savedIssues,
188				});
189	
190				await this.storeWorklogs({
191					installationDbId,
192					cloudId,
193					token,
194					issues: response.issues,
195					savedIssues,
196				});
197	
198				startAt += pageSize;
199				if (startAt >= response.total || response.issues.length < pageSize) break;
200			}
201		}
202	
203		private async storeChangelogs({
204			installationDbId,
205			issues,
206			savedIssues,
207		}: {
208			installationDbId: string;
209			issues: IJiraApiIssue[];
210			savedIssues: IJiraIssueBase[];
211		}): Promise<void> {
212			const issueDbIdMap = new Map(savedIssues.map((i) => [i.issue_id, i._id]));
213			const entries: Array<{
214				issue_id: string;
215				installation_id: string;
216				jira_history_id: string;
217				author_id: string | null;
218				field: string;
219				from_value: string | null;
220				to_value: string | null;
221				changed_at: Date;
222			}> = [];
223	
224			for (const issue of issues) {
225				const issueDbId = issueDbIdMap.get(issue.id);
226				if (!issueDbId || !issue.changelog) continue;
227	
228				for (const history of issue.changelog.histories) {
229					for (const item of history.items) {
230						entries.push({
231							issue_id: issueDbId,
232							installation_id: installationDbId,
233							jira_history_id: history.id,
234							author_id: history.author?.accountId ?? null,
235							field: item.field,
236							from_value: item.fromString,
237							to_value: item.toString,
238							changed_at: new Date(history.created),
239						});
240					}
241				}
242			}
243	
244			await this.changelogModel.upsertMany({ entries });
245		}
246	
247		private async storeWorklogs({
248			installationDbId,
249			cloudId,
250			token,
251			issues,
252			savedIssues,
253		}: {
254			installationDbId: string;
255			cloudId: string;
256			token: string;
257			issues: IJiraApiIssue[];
258			savedIssues: IJiraIssueBase[];
259		}): Promise<void> {
260			const issueDbIdMap = new Map(savedIssues.map((i) => [i.issue_id, i._id]));
261	
262			for (const issue of issues) {
263				const issueDbId = issueDbIdMap.get(issue.id);
264				if (!issueDbId) continue;
265	
266				const worklogs = await this.jiraApiService.getWorklogsForIssue({
267					cloudId,
268					token,
269					issueId: issue.id,
270				});
271	
272				if (worklogs.length === 0) continue;
273	
274				await this.worklogModel.upsertMany({
275					worklogs: worklogs.map((w) => ({
276						issue_id: issueDbId,
277						installation_id: installationDbId,
278						jira_worklog_id: w.id,
279						author_id: w.author?.accountId ?? null,
280						time_spent_sec: w.timeSpentSeconds,
281						started_at: w.started ? new Date(w.started) : null,
282						updated_at: new Date(w.updated),
283					})),
284				});
285			}
286		}
287	
288		private async fetchAndStoreSprints({
289			installationDbId,
290			projectKey,
291			cloudId,
292			token,
293		}: {
294			installationDbId: string;
295			projectKey: string;
296			cloudId: string;
297			token: string;
298		}): Promise<void> {
299			try {
300				const boardsResponse = await this.jiraApiService.listBoards({
301					cloudId,
302					token,
303					projectKeyOrId: projectKey,
304				});
305	
306				for (const board of boardsResponse.values) {
307					let startAt = 0;
308					while (true) {
309						const sprintResponse = await this.jiraApiService.listSprints({
310							cloudId,
311							token,
312							boardId: board.id,
313							startAt,
314						});
315	
316						await this.sprintModel.upsertMany({
317							installationId: installationDbId,
318							boardId: String(board.id),
319							sprints: sprintResponse.values,
320						});
321	
322						if (sprintResponse.isLast || sprintResponse.values.length === 0) break;
323						startAt += 50;
324					}
325				}
326			} catch (error) {
327				this.logger.warn(
328					`Failed to fetch sprints for project ${projectKey}: ${(error as Error).message}`,
329				);
330			}
331		}
332	}
